const ai = $node["AI_Node (Cerebro)"].json;
const prepData = $node["Prepare Data (L谩piz)"].json;
const rawContent = ai.choices?.[0]?.message?.content || "{}";
let parsed = {};
try {
  parsed = JSON.parse(rawContent.replace(/```json|```/g, '').trim());
} catch (e) {
  parsed = { categoria: "CAT_VARIOS", translations: { es: { titulo: "Error AI", descripcion: "Parse failure" } } };
}

const validCats = ["CAT_PLAZAS", "CAT_EVENTOS", "CAT_AGENCY", "CAT_MODELOS", "CAT_VARIOS"];
let finalCat = parsed.categoria;
const rawText = (prepData.text || "").toLowerCase();

if (!validCats.includes(finalCat)) {
    if (rawText.includes("fija") || rawText.includes("staff") || rawText.includes("club")) {
        finalCat = "CAT_PLAZAS";
    } else {
        finalCat = "CAT_VARIOS";
    }
}

const external_id = prepData.message_id || Math.abs(rawText.split('').reduce((a,b)=>{a=((a<<5)-a)+b.charCodeAt(0);return a&a},0)).toString();

return {
  categoria: finalCat,
  translations: parsed.translations,
  ubicacion: parsed.ubicacion || "Global",
  contacto: parsed.contacto || "Ver en Telegram",
  activa: true,
  timestamp: new Date().toISOString(),
  platform: "TELEGRAM",
  external_id: external_id.toString()
};
